class UATEvidencePayload(BaseModel):
    model_config = ConfigDict(
        extra='forbid',
        populate_by_name=True,
    )
    domain: str
    workspace: str
    captured_at: AwareDatetime = Field(..., alias='capturedAt')
    adapter_mode: Literal['mock', 'legacy-api', 'databricks-api'] = Field(
        ..., alias='adapterMode'
    )
    inputs: dict[
        str,
        Union[
            Optional[Union[str, float, bool]],
            list[Optional[AdditionalProperties]],
            dict[str, Optional[AdditionalProperties]],
        ],
    ]
    source_summary: SourceSummary = Field(..., alias='sourceSummary')
    evidence_completeness: EvidenceCompleteness = Field(
        ..., alias='evidenceCompleteness'
    )
    counts: Optional[dict[str, float]] = None
    warnings: list[str]
    uat_notes: Optional[list[str]] = Field(
        [
            'No live validation claimed.',
            'Unavailable evidence must not be interpreted as zero exposure or no risk.',
        ],
        alias='uatNotes',
    )


AdditionalProperties.model_rebuild()
